function GetNossoNumero: string;
begin
  Result := <Boleto."CARTEIRA"> + '/' + <Boleto."NOSSO_NUMERO"> + '-' + <Boleto."DIGITO_NOSSO_NUMERO">;                                                    
end;

function GetConta: string;
begin
  Result := <Boleto."AGENCIA"> + '-' + <Boleto."DIGITO_AGENCIA"> + '/' + <Boleto."CONTA"> + '-' + <Boleto."DIGITO_CONTA">;                                                                                                             
end;          
  
begin

end.
